queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTasks ?child ; p:hasAssistants ?parent . } GROUP BY ?child }
  ?child p:task_name ?task_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Assistants } }
  FILTER(?nf = ?total)
}

